import { createStreamableValue } from 'ai/rsc';
import { streamText } from 'ai';
import { openai } from '@ai-sdk/openai';
import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

export async function detectStreamDrift(input: string) {
  const stream = await streamText({
    model: openai('gpt-4o'),
    prompt: input,
  });

  const vexStream = vex.monitorStream(stream, {
    detector: 'hallucination',
    threshold: 0.3,
    groundTruth: 'Expected factual response about topic',
  });

  let hasDrift = false;
  for await (const chunk of vexStream) {
    if (chunk.vex?.driftDetected) {
      hasDrift = true;
      console.warn('Hallucination detected:', chunk.vex.evidence);
    }
  }

  return { hasDrift, stream };
}
