  // Vex validation layer
  const validated = await vex.validateOutput(result, {
    schema: ToolSchema,
    detector: 'tool-drift',
  });

  if (!validated.valid) {
    throw new Error(`Tool drift: ${validated.errors}`);
  }

  return result;
}
