export async function monitorAgentLatency(input: string) {
  const start = Date.now();
  const stream = await streamText({
    model: openai('gpt-4o'),
    tools: { /* complex toolset */ },
    prompt: input,
  });

  const monitored = vex.monitorStream(stream, {
    detector: 'performance',
    timeoutThreshold: 25000, // 25s before Vercel edge timeout
    latencyAlert: 15000,
  });

  let totalDuration = 0;
  for await (const chunk of monitored) {
    if (chunk.vex?.timeoutRisk) {
      console.warn('Edge timeout imminent:', chunk.vex.remainingMs);
    }
    totalDuration = Date.now() - start;
  }

  return { stream, metrics: { totalDuration } };
}
