import { createStreamableValue } from 'ai/rsc';
import { streamText } from 'ai';
import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

export default async function SafeStreamUI({ prompt }: { prompt: string }) {
  const stream = createStreamableValue();

  (async () => {
    try {
      const textStream = await streamText({
        model: openai('gpt-4o'),
        prompt,
      });

      const safeStream = vex.filterStream(textStream, {
        blocks: ['harmful', 'hallucination'],
        fallback: 'I need to verify this information...',
      });

      let result = '';
      for await (const chunk of safeStream) {
        result += chunk;
        stream.update(result);
      }
      stream.done();
    } catch (error) {
      stream.error(error);
    }
  })();

  return stream.value;
}
