import { generateObject, generateText } from 'ai';
import { z } from 'zod';
import { Vex } from '@vex_dev/sdk';

const ResponseSchema = z.object({
  intent: z.string(),
  confidence: z.number().min(0.7),
  action: z.string().optional(),
});

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

export async function guardedAgent(input: string) {
  // Try structured first
  try {
    const result = await generateObject({
      model: openai('gpt-4o'),
      schema: ResponseSchema,
      prompt: input,
    });
    return result;
  } catch (e) {
    // Fallback with Vex normalization
    const text = await generateText({ model: openai('gpt-4o'), prompt: input });
    const normalized = await vex.normalizeToSchema(text, ResponseSchema);
    return normalized;
  }
}
