import { streamText } from 'ai';
import { Vex } from '@vex_dev/sdk';

const vex = new Vex({ apiKey: process.env.VEX_API_KEY! });

export async function smartAgentTask(input: string) {
  // Quick response for UI
  const quickStream = await streamText({
    model: openai('gpt-4o-mini'),
    maxTokens: 50,
    prompt: `Acknowledge: ${input}`,
  });

  // Complex task in background
  const taskId = await vex.queueAgentTask({
    input,
    model: openai('gpt-4o'),
    tools: true,
    maxDuration: 300000, // 5min
  });

  return {
    immediate: quickStream,
    taskId,
    status: await vex.getTaskStatus(taskId),
  };
}
