import { createMiddleware } from '@vex_dev/sdk/vercel';
import { generateText, streamText, generateObject } from 'ai';

export const vexMiddleware = createMiddleware({
  apiKey: process.env.VEX_API_KEY!,
  detectors: {
    hallucination: { threshold: 0.25 },
    schema: { strict: true },
    performance: { timeout: 25000 },
  },
  autoRemediate: true,
});

// All AI calls automatically monitored
export async function monitoredStream(input: string) {
  return streamText({
    model: openai('gpt-4o'),
    prompt: input,
  }); // Vex middleware wraps automatically
}

// Works with RSC too
export default async function AgentUI({ input }: { input: string }) {
  const { textStream } = await monitoredStream(input);
  // Vex drift signals available in headers
  return <StreamRenderer stream={textStream} />;
}
